<?php
require_once __DIR__.'/auth.php';
require_once __DIR__.'/partials/layout.php';
require_login();
$items=[];$r=mysqli_query($koneksi,"SELECT k.id_kategori,k.nama_kategori,k.deskripsi,COUNT(DISTINCT a.id_arsip) archive_count,COUNT(af.id_file) file_count,MAX(a.tanggal_acara) latest_event,
(SELECT af2.filename FROM arsip_file af2 JOIN arsip a2 ON a2.id_arsip=af2.id_arsip WHERE a2.id_kategori=k.id_kategori AND LOWER(af2.tipe_file) IN('jpg','jpeg','png','gif','webp') ORDER BY af2.id_file DESC LIMIT 1) cover
FROM kategori k LEFT JOIN arsip a ON a.id_kategori=k.id_kategori LEFT JOIN arsip_file af ON af.id_arsip=a.id_arsip
GROUP BY k.id_kategori,k.nama_kategori,k.deskripsi ORDER BY latest_event DESC,k.nama_kategori");
if($r)while($x=mysqli_fetch_assoc($r))$items[]=$x;
$totalArchives=0;$totalFiles=0;foreach($items as $x){$totalArchives+=(int)$x['archive_count'];$totalFiles+=(int)$x['file_count'];}
render_app_start('Arsip','Pilih kategori untuk melihat galeri dan dokumen kegiatan.','arsip.php'); ?>
<section class="hero"><div class="hero-copy"><span class="hero-kicker">Perpustakaan Digital</span><h2>Temukan kembali setiap kegiatan dengan lebih cepat.</h2><p>Setiap folder kategori berisi galeri foto dan dokumen pendukung. Gunakan pencarian untuk menemukan bidang atau kegiatan yang dibutuhkan.</p></div><div class="hero-actions"><a class="btn btn-light" href="kategori.php"><i class="fa-solid fa-layer-group"></i> Kelola Kategori</a></div></section>
<section class="stats-grid"><article class="stat-card"><span class="stat-icon blue"><i class="fa-solid fa-folder-tree"></i></span><div class="stat-copy"><strong><?=count($items)?></strong><span>Folder kategori</span></div></article><article class="stat-card"><span class="stat-icon purple"><i class="fa-solid fa-box-archive"></i></span><div class="stat-copy"><strong><?=$totalArchives?></strong><span>Arsip kegiatan</span></div></article><article class="stat-card"><span class="stat-icon green"><i class="fa-solid fa-paperclip"></i></span><div class="stat-copy"><strong><?=$totalFiles?></strong><span>File tersimpan</span></div></article><article class="stat-card"><span class="stat-icon orange"><i class="fa-regular fa-calendar-check"></i></span><div class="stat-copy"><strong><?=date('Y')?></strong><span>Tahun aktif</span></div></article></section>
<section class="panel section-gap"><header class="panel-header"><div class="panel-title"><h2>Koleksi arsip</h2><p>Buka salah satu kategori untuk mengelola isinya.</p></div><div class="toolbar"><label class="search-box"><i class="fa-solid fa-magnifying-glass"></i><input class="input" type="search" placeholder="Cari folder..." data-live-search=".archive-folder" data-empty-target="#archiveSearchEmpty"></label></div></header><div class="panel-body">
<?php if($items):?><div class="category-grid"><?php foreach($items as $item):?><a class="category-card archive-folder" data-search="<?=e($item['nama_kategori'].' '.$item['deskripsi'])?>" href="arsip_tambah.php?id_kategori=<?=(int)$item['id_kategori']?>" style="display:block">
<div class="archive-cover" style="height:170px;border-radius:14px;margin:-2px -2px 16px"><?php if($item['cover']):?><img src="uploads/<?=e($item['cover'])?>" alt="<?=e($item['nama_kategori'])?>"><?php else:?><div class="file-placeholder"><span><i class="fa-solid fa-folder-open"></i><br>Belum ada gambar</span></div><?php endif;?><span class="archive-count"><?=(int)$item['archive_count']?> arsip</span></div>
<h3><?=e($item['nama_kategori'])?></h3><p><?=e($item['deskripsi']?:'Belum ada deskripsi kategori.')?></p><div class="card-meta"><span><i class="fa-solid fa-paperclip"></i> <?=(int)$item['file_count']?> file</span><span><i class="fa-regular fa-calendar"></i> <?=e($item['latest_event']?format_date_id($item['latest_event']):'Belum ada kegiatan')?></span></div><div class="card-actions"><span class="btn btn-secondary btn-sm">Buka Galeri <i class="fa-solid fa-arrow-right"></i></span></div></a><?php endforeach;?></div><div id="archiveSearchEmpty" class="empty-state" hidden><i class="fa-solid fa-magnifying-glass"></i><h3>Folder tidak ditemukan</h3><p>Coba gunakan kata pencarian lain.</p></div>
<?php else:?><div class="empty-state"><i class="fa-regular fa-folder-open"></i><h3>Belum ada kategori arsip</h3><p>Buat kategori terlebih dahulu untuk mulai mengunggah dokumentasi.</p><a class="btn btn-primary" href="kategori.php">Buat kategori</a></div><?php endif;?></div></section>
<?php render_app_end(); ?>